// Late binding using reflection and COM
Type comType = Type.GetTypeFromProgID("MyCustom.Application");
object obj = Activator.CreateInstance(comType);
object result = comType.InvokeMember("DoSomething", 
    BindingFlags.InvokeMethod, null, obj, new object[] { "parameter" });

// Release COM object
if (obj != null && Marshal.IsComObject(obj))
{
    Marshal.ReleaseComObject(obj);
}

