com_error_handling.csharp_equivalent:
try
{
    Type comType = Type.GetTypeFromProgID("NonExistent.Application");
    if (comType == null)
    {
        throw new COMException("COM class not registered");
    }
    object obj = Activator.CreateInstance(comType);
}
catch (COMException ex)
{
    MessageBox.Show($"COM Error: {ex.Message}");
}
catch (Exception ex)
{
    MessageBox.Show($"Error: {ex.Message}");
}

